+const std = @import("std");
+const logger = @import("logger.zig");
+
+// =============================================================================
+// Dream Corpus: Reference Data for Q-Healing Calibration
+// =============================================================================
+//
+// During Q-Healing, we need calibration data to compare Q2_K vs FP16 outputs.
+// Using ONLY user conversation logs causes overfitting to user-specific patterns.
+// Using random noise destroys model coherence.
+//
+// Solution: Mix 50% reference corpus + 50% user conversation logs.
+// The reference corpus provides domain-balanced "textbook" material that keeps
+// the model's general capabilities intact while still personalizing to the user.
+// =============================================================================
+
+/// Corpus source types for mixed training
+pub const CorpusSource = enum(u8) {
+    /// Wikipedia-style general knowledge
+    wiki_general,
+    /// Programming code samples
+    code_samples,
+    /// Logic and math reasoning
+    reasoning,
+    /// User conversation history (from conversation_logger)
+    conversation_log,
+    /// User-provided custom corpus
+    custom,
+
+    pub fn toFilename(self: CorpusSource) ?[]const u8 {
+        return switch (self) {
+            .wiki_general => "wiki_subset.txt",
+            .code_samples => "code_samples.txt",
+            .reasoning => "reasoning.txt",
+            .conversation_log => null, // Not a file
+            .custom => "custom/corpus.txt",
+        };
+    }
+
+    pub fn toString(self: CorpusSource) []const u8 {
+        return switch (self) {
+            .wiki_general => "wiki_general",
+            .code_samples => "code_samples",
+            .reasoning => "reasoning",
+            .conversation_log => "conversation_log",
+            .custom => "custom",
+        };
+    }
+};
+
+/// Configuration for corpus mixing during Q-Healing
+pub const CorpusMixConfig = struct {
+    /// Ratio of corpus data to user data (0.5 = 50/50 mix)
+    corpus_ratio: f32 = 0.5,
+
+    /// Enable shuffling of mixed samples
+    shuffle: bool = true,
+
+    /// Maximum tokens to sample per corpus source
+    max_tokens_per_source: u32 = 4096,
+
+    /// Enable domain balancing (equal weight per source type)
+    domain_balanced: bool = true,
+
+    /// Chunk size for sampling (approximate tokens)
+    chunk_size: usize = 1024,
+
+    /// Minimum text length to consider valid
+    min_text_length: usize = 64,
+};
+
+/// Corpus manifest for tracking sources and checksums
+pub const CorpusManifest = struct {
+    /// Manifest version
+    version: u32,
+    /// Source entries
+    sources: []CorpusSourceEntry,
+    /// Total estimated tokens across all sources
+    total_tokens: u64,
+    /// Last update timestamp
+    last_updated: i64,
+
+    pub fn deinit(self: *CorpusManifest, allocator: std.mem.Allocator) void {
+        for (self.sources) |*entry| {
+            allocator.free(entry.filename);
+        }
+        allocator.free(self.sources);
+    }
+};
+
+/// Individual corpus source entry in manifest
+pub const CorpusSourceEntry = struct {
+    /// Source type
+    source_type: CorpusSource,
+    /// Filename relative to corpus directory
+    filename: []const u8,
+    /// File size in bytes
+    size_bytes: usize,
+    /// Estimated token count
+    token_count: u64,
+    /// CRC32 checksum for integrity
+    checksum: u32,
+};
+
+/// Statistics about corpus usage
+pub const CorpusStats = struct {
+    /// Whether corpus directory exists and has data
+    is_available: bool,
+    /// Number of sources currently loaded in cache
+    sources_loaded: usize,
+    /// Total bytes cached in memory
+    total_cached_bytes: usize,
+    /// Sources that failed to load
+    failed_sources: usize,
+};
+
+/// Main Dream Corpus manager
+pub const DreamCorpus = struct {
+    allocator: std.mem.Allocator,
+
+    /// Path to corpus directory (~/.cache/zell/corpus/)
+    corpus_dir: []const u8,
+
+    /// Mixing configuration
+    config: CorpusMixConfig,
+
+    /// Cached corpus data (source type -> text content)
+    cached_sources: std.AutoHashMap(CorpusSource, []u8),
+
+    /// Random state for sampling
+    prng: std.Random.DefaultPrng,
+
+    /// Track failed source loads
+    failed_sources: std.AutoHashMap(CorpusSource, bool),
+
+    const Self = @This();
+
+    /// Initialize the Dream Corpus manager
+    pub fn init(allocator: std.mem.Allocator) !Self {
+        const home = std.posix.getenv("HOME") orelse "/tmp";
+        const corpus_dir = try std.fmt.allocPrint(
+            allocator,
+            "{s}/.cache/zell/corpus",
+            .{home},
+        );
+        errdefer allocator.free(corpus_dir);
+
+        // Ensure directory exists
+        std.fs.cwd().makePath(corpus_dir) catch |err| {
+            if (err != error.PathAlreadyExists) {
+                logger.warn("Failed to create corpus directory: {}", .{err});
+            }
+        };
+
+        return Self{
+            .allocator = allocator,
+            .corpus_dir = corpus_dir,
+            .config = CorpusMixConfig{},
+            .cached_sources = std.AutoHashMap(CorpusSource, []u8).init(allocator),
+            .prng = std.Random.DefaultPrng.init(@intCast(@as(u64, @bitCast(std.time.timestamp())))),
+            .failed_sources = std.AutoHashMap(CorpusSource, bool).init(allocator),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        // Free cached source data
+        var it = self.cached_sources.iterator();
+        while (it.next()) |entry| {
+            self.allocator.free(entry.value_ptr.*);
+        }
+        self.cached_sources.deinit();
+        self.failed_sources.deinit();
+        self.allocator.free(self.corpus_dir);
+    }
+
+    /// Check if any corpus data is available
+    pub fn isAvailable(self: *Self) bool {
+        // Check for manifest or any source files
+        const manifest_path = std.fmt.allocPrint(
+            self.allocator,
+            "{s}/manifest.json",
+            .{self.corpus_dir},
+        ) catch return false;
+        defer self.allocator.free(manifest_path);
+
+        if (std.fs.cwd().access(manifest_path, .{})) |_| {
+            return true;
+        } else |_| {}
+
+        // Check for individual source files
+        const sources = [_]CorpusSource{ .wiki_general, .code_samples, .reasoning };
+        for (sources) |source| {
+            if (source.toFilename()) |filename| {
+                const path = std.fmt.allocPrint(
+                    self.allocator,
+                    "{s}/{s}",
+                    .{ self.corpus_dir, filename },
+                ) catch continue;
+                defer self.allocator.free(path);
+
+                if (std.fs.cwd().access(path, .{})) |_| {
+                    return true;
+                } else |_| {}
+            }
+        }
+
+        return false;
+    }
+
+    /// Load a corpus source (lazy, with caching)
+    pub fn loadSource(self: *Self, source: CorpusSource) ![]const u8 {
+        // Check cache first
+        if (self.cached_sources.get(source)) |data| {
+            return data;
+        }
+
+        // Check if previously failed
+        if (self.failed_sources.get(source)) |_| {
+            return error.SourcePreviouslyFailed;
+        }
+
+        // Conversation log is not a file - must be provided externally
+        if (source == .conversation_log) {
+            return error.UseConversationLogger;
+        }
+
+        const filename = source.toFilename() orelse return error.InvalidSource;
+
+        const path = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/{s}",
+            .{ self.corpus_dir, filename },
+        );
+        defer self.allocator.free(path);
+
+        const file = std.fs.cwd().openFile(path, .{}) catch |err| {
+            logger.debug("Corpus source not found: {s} ({})", .{ path, err });
+            try self.failed_sources.put(source, true);
+            return error.SourceNotFound;
+        };
+        defer file.close();
+
+        // Limit to 100MB per source
+        const max_size: usize = 100 * 1024 * 1024;
+        const data = file.readToEndAlloc(self.allocator, max_size) catch |err| {
+            logger.warn("Failed to read corpus source {s}: {}", .{ path, err });
+            try self.failed_sources.put(source, true);
+            return err;
+        };
+
+        try self.cached_sources.put(source, data);
+
+        logger.debug("Loaded corpus source: {s} ({d} KB)", .{
+            source.toString(),
+            data.len / 1024,
+        });
+
+        return data;
+    }
+
+    /// Unload a cached source to free memory
+    pub fn unloadSource(self: *Self, source: CorpusSource) void {
+        if (self.cached_sources.fetchRemove(source)) |entry| {
+            self.allocator.free(entry.value);
+        }
+    }
+
+    /// Unload all cached sources
+    pub fn unloadAll(self: *Self) void {
+        var it = self.cached_sources.iterator();
+        while (it.next()) |entry| {
+            self.allocator.free(entry.value_ptr.*);
+        }
+        self.cached_sources.clearRetainingCapacity();
+    }
+
+    /// Sample mixed training data (corpus + user data)
+    /// Returns owned slices that caller must free
+    pub fn sampleMixedData(
+        self: *Self,
+        user_data: []const []const u8,
+        total_samples: usize,
+    ) ![][]u8 {
+        var samples = try std.ArrayList([]u8).initCapacity(self.allocator, total_samples);
+        errdefer {
+            for (samples.items) |s| self.allocator.free(s);
+            samples.deinit();
+        }
+
+        // Calculate sample counts based on ratio
+        const corpus_count: usize = @intFromFloat(@as(f32, @floatFromInt(total_samples)) * self.config.corpus_ratio);
+        const user_count = total_samples - corpus_count;
+
+        logger.debug("Sampling {d} corpus + {d} user = {d} total", .{
+            corpus_count,
+            user_count,
+            total_samples,
+        });
+
+        // Sample from corpus sources
+        if (corpus_count > 0) {
+            try self.sampleFromCorpus(&samples, corpus_count);
+        }
+
+        // Sample from user data
+        if (user_count > 0 and user_data.len > 0) {
+            try self.sampleFromUserData(&samples, user_data, user_count);
+        }
+
+        // Shuffle if configured
+        if (self.config.shuffle and samples.items.len > 1) {
+            self.shuffleSamples(samples.items);
+        }
+
+        logger.info("Dream corpus: sampled {d} mixed entries ({d} corpus, {d} user)", .{
+            samples.items.len,
+            @min(corpus_count, samples.items.len),
+            samples.items.len -| @min(corpus_count, samples.items.len),
+        });
+
+        return samples.toOwnedSlice();
+    }
+
+    /// Sample from corpus sources with domain balancing
+    fn sampleFromCorpus(self: *Self, samples: *std.ArrayList([]u8), count: usize) !void {
+        const sources = [_]CorpusSource{ .wiki_general, .code_samples, .reasoning };
+
+        // Calculate samples per source (domain balanced or proportional)
+        const samples_per_source = if (self.config.domain_balanced)
+            count / sources.len
+        else
+            count; // All from first available
+
+        var total_sampled: usize = 0;
+
+        for (sources) |source| {
+            if (total_sampled >= count) break;
+
+            const target = @min(samples_per_source, count - total_sampled);
+            const source_data = self.loadSource(source) catch continue;
+
+            const sampled = try self.sampleChunksFromText(samples, source_data, target);
+            total_sampled += sampled;
+        }
+
+        // If we didn't get enough, try to sample more from available sources
+        if (total_sampled < count) {
+            for (sources) |source| {
+                if (total_sampled >= count) break;
+
+                const source_data = self.loadSource(source) catch continue;
+                const remaining = count - total_sampled;
+                const sampled = try self.sampleChunksFromText(samples, source_data, remaining);
+                total_sampled += sampled;
+            }
+        }
+    }
+
+    /// Sample chunks from a text source
+    fn sampleChunksFromText(
+        self: *Self,
+        samples: *std.ArrayList([]u8),
+        text: []const u8,
+        count: usize,
+    ) !usize {
+        if (text.len < self.config.min_text_length) return 0;
+
+        const chunk_size = self.config.chunk_size;
+        const num_possible_chunks = text.len / chunk_size;
+
+        if (num_possible_chunks == 0) {
+            // Text is smaller than chunk size, take whole thing
+            if (text.len >= self.config.min_text_length) {
+                const copy = try self.allocator.dupe(u8, text);
+                try samples.append(copy);
+                return 1;
+            }
+            return 0;
+        }
+
+        var sampled: usize = 0;
+        const random = self.prng.random();
+
+        // Sample random chunks
+        var attempts: usize = 0;
+        const max_attempts = count * 3; // Prevent infinite loops
+
+        while (sampled < count and attempts < max_attempts) : (attempts += 1) {
+            const chunk_idx = random.intRangeLessThan(usize, 0, num_possible_chunks);
+            const start = chunk_idx * chunk_size;
+            const end = @min(start + chunk_size, text.len);
+
+            const chunk = text[start..end];
+
+            // Skip if too short or mostly whitespace
+            if (chunk.len < self.config.min_text_length) continue;
+
+            var whitespace_count: usize = 0;
+            for (chunk) |c| {
+                if (std.ascii.isWhitespace(c)) whitespace_count += 1;
+            }
+            if (whitespace_count > chunk.len * 3 / 4) continue; // >75% whitespace
+
+            const copy = try self.allocator.dupe(u8, chunk);
+            try samples.append(copy);
+            sampled += 1;
+        }
+
+        return sampled;
+    }
+
+    /// Sample from user conversation data
+    fn sampleFromUserData(
+        self: *Self,
+        samples: *std.ArrayList([]u8),
+        user_data: []const []const u8,
+        count: usize,
+    ) !void {
+        if (user_data.len == 0) return;
+
+        const random = self.prng.random();
+        var sampled: usize = 0;
+
+        // If we have fewer user entries than needed, use all of them
+        if (user_data.len <= count) {
+            for (user_data) |entry| {
+                if (entry.len >= self.config.min_text_length) {
+                    const copy = try self.allocator.dupe(u8, entry);
+                    try samples.append(copy);
+                    sampled += 1;
+                }
+            }
+            return;
+        }
+
+        // Random sampling without replacement
+        var indices = try self.allocator.alloc(usize, user_data.len);
+        defer self.allocator.free(indices);
+
+        for (indices, 0..) |*idx, i| {
+            idx.* = i;
+        }
+
+        // Fisher-Yates shuffle then take first 'count'
+        var i = indices.len;
+        while (i > 1) {
+            i -= 1;
+            const j = random.intRangeLessThan(usize, 0, i + 1);
+            const tmp = indices[i];
+            indices[i] = indices[j];
+            indices[j] = tmp;
+        }
+
+        for (indices[0..@min(count, indices.len)]) |idx| {
+            const entry = user_data[idx];
+            if (entry.len >= self.config.min_text_length) {
+                const copy = try self.allocator.dupe(u8, entry);
+                try samples.append(copy);
+                sampled += 1;
+
+                if (sampled >= count) break;
+            }
+        }
+    }
+
+    /// Shuffle samples in place
+    fn shuffleSamples(self: *Self, items: [][]u8) void {
+        const random = self.prng.random();
+        var i = items.len;
+        while (i > 1) {
+            i -= 1;
+            const j = random.intRangeLessThan(usize, 0, i + 1);
+            const tmp = items[i];
+            items[i] = items[j];
+            items[j] = tmp;
+        }
+    }
+
+    /// Get corpus statistics
+    pub fn getStats(self: *Self) CorpusStats {
+        var total_bytes: usize = 0;
+        var it = self.cached_sources.iterator();
+        while (it.next()) |entry| {
+            total_bytes += entry.value_ptr.len;
+        }
+
+        return CorpusStats{
+            .is_available = self.isAvailable(),
+            .sources_loaded = self.cached_sources.count(),
+            .total_cached_bytes = total_bytes,
+            .failed_sources = self.failed_sources.count(),
+        };
+    }
+
+    /// Set mixing configuration
+    pub fn setConfig(self: *Self, config: CorpusMixConfig) void {
+        self.config = config;
+    }
+
+    /// Get corpus directory path
+    pub fn getCorpusDir(self: *const Self) []const u8 {
+        return self.corpus_dir;
+    }
+};
+
+// =============================================================================
+// Corpus Generation Utilities
+// =============================================================================
+
+/// Generate a default corpus manifest
+pub fn generateDefaultManifest(allocator: std.mem.Allocator) !CorpusManifest {
+    var sources = try allocator.alloc(CorpusSourceEntry, 3);
+
+    sources[0] = .{
+        .source_type = .wiki_general,
+        .filename = try allocator.dupe(u8, "wiki_subset.txt"),
+        .size_bytes = 0,
+        .token_count = 0,
+        .checksum = 0,
+    };
+
+    sources[1] = .{
+        .source_type = .code_samples,
+        .filename = try allocator.dupe(u8, "code_samples.txt"),
+        .size_bytes = 0,
+        .token_count = 0,
+        .checksum = 0,
+    };
+
+    sources[2] = .{
+        .source_type = .reasoning,
+        .filename = try allocator.dupe(u8, "reasoning.txt"),
+        .size_bytes = 0,
+        .token_count = 0,
+        .checksum = 0,
+    };
+
