+/// Rate limiting for deep sleep cycles
+pub const DeepSleepRateLimit = struct {
+    /// Timestamps of completed deep sleep cycles (Unix ms)
+    cycle_timestamps: std.ArrayList(i64),
+    /// Currently in a deep sleep cycle
+    in_cycle: bool = false,
+    /// Start time of current cycle
