+    pub fn init(allocator: std.mem.Allocator) DeepSleepRateLimit {
+        return .{
+            .cycle_timestamps = std.ArrayList(i64).init(allocator),
+            .allocator = allocator,
+        };
+    }
+
+    pub fn deinit(self: *DeepSleepRateLimit) void {
+        self.cycle_timestamps.deinit(self.allocator);
+    }
+
+    /// Count cycles in the last 24 hours
+    pub fn cyclesInLast24Hours(self: *DeepSleepRateLimit) u32 {
+        const now = std.time.milliTimestamp();
+        const cutoff = now - (24 * 60 * 60 * 1000); // 24 hours ago
+
+        var count: u32 = 0;
+        for (self.cycle_timestamps.items) |ts| {
+            if (ts > cutoff) {
+                count += 1;
+            }
+        }
+        return count;
+    }
+
+    /// Get time until next cycle is allowed (ms)
+    pub fn timeUntilNextAllowed(self: *DeepSleepRateLimit, cooldown_ms: i64) ?i64 {
+        if (self.cycle_timestamps.items.len == 0) return null;
+
+        const last = self.cycle_timestamps.items[self.cycle_timestamps.items.len - 1];
+        const now = std.time.milliTimestamp();
+        const next_allowed = last + cooldown_ms;
+
+        if (now >= next_allowed) return null;
+        return next_allowed - now;
+    }
+
+    /// Prune old timestamps (older than 24 hours)
+    pub fn pruneOld(self: *DeepSleepRateLimit) void {
+        const now = std.time.milliTimestamp();
+        const cutoff = now - (24 * 60 * 60 * 1000);
+
+        // Remove timestamps older than 24 hours
+        var i: usize = 0;
+        while (i < self.cycle_timestamps.items.len) {
+            if (self.cycle_timestamps.items[i] < cutoff) {
+                _ = self.cycle_timestamps.orderedRemove(i);
+            } else {
+                i += 1;
+            }
+        }
+    }
