+/// Query battery status on macOS using pmset
+fn queryBatteryStatusMacOS(allocator: std.mem.Allocator) !BatteryStatus {
+    // Run: pmset -g batt
+    // Example output:
+    // Now drawing from 'AC Power'
+    //  -InternalBattery-0 (id=...)  100%; charged; 0:00 remaining
+    // OR
+    // Now drawing from 'Battery Power'
+    //  -InternalBattery-0 (id=...)  85%; discharging; 3:45 remaining
+
+    var child = std.process.Child.init(&[_][]const u8{ "pmset", "-g", "batt" }, allocator);
+    child.stdout_behavior = .Pipe;
+    child.stderr_behavior = .Ignore;
+
+    try child.spawn();
+
+    const stdout = child.stdout orelse return error.NoStdout;
+    const output = try stdout.readToEndAlloc(allocator, 4096);
+    defer allocator.free(output);
+
+    const term = try child.wait();
+    if (term.Exited != 0) return error.CommandFailed;
+
+    return parsePmsetOutput(output);
+}
+
+/// Parse pmset -g batt output
+fn parsePmsetOutput(output: []const u8) BatteryStatus {
+    var status = BatteryStatus{
+        .source = .unknown,
+        .percentage = null,
+        .is_charging = false,
+    };
+
+    var lines = std.mem.splitScalar(u8, output, '\n');
+
+    while (lines.next()) |line| {
+        // Check power source
+        if (std.mem.indexOf(u8, line, "'AC Power'")) |_| {
+            status.source = .ac;
+        } else if (std.mem.indexOf(u8, line, "'Battery Power'")) |_| {
+            status.source = .battery;
+        }
+
+        // Check for battery percentage (e.g., "85%;")
+        if (std.mem.indexOf(u8, line, "%;")) |pct_end| {
+            // Find start of percentage number
+            var pct_start = pct_end;
+            while (pct_start > 0 and std.ascii.isDigit(line[pct_start - 1])) {
+                pct_start -= 1;
+            }
+            if (pct_start < pct_end) {
+                status.percentage = std.fmt.parseInt(u8, line[pct_start..pct_end], 10) catch null;
+            }
+        }
+
+        // Check charging status
+        if (std.mem.indexOf(u8, line, "charging")) |_| {
+            if (std.mem.indexOf(u8, line, "discharging") == null and
+                std.mem.indexOf(u8, line, "not charging") == null)
+            {
+                status.is_charging = true;
+            }
+        } else if (std.mem.indexOf(u8, line, "charged")) |_| {
+            status.is_charging = false; // Fully charged, not actively charging
+        }
+    }
+
+    return status;
+}
