+/// Query thermal pressure on macOS using sysctl
+fn queryThermalPressureMacOS() !ThermalPressure {
+    // sysctl kern.thermal_level returns:
+    // 0 = nominal
+    // 1+ = elevated (we map to fair/serious/critical)
+
+    var buf: [64]u8 = undefined;
+    var len: usize = buf.len;
+
+    // Use sysctlbyname to query kern.thermal_level
+    const name = "kern.thermal_level";
+    const result = std.c.sysctlbyname(
+        name,
+        &buf,
+        &len,
+        null,
+        0,
+    );
+
+    if (result != 0) {
+        // Fallback: assume nominal if sysctlbyname fails
+        return .nominal;
+    }
+
+    // Parse the integer value
+    if (len >= 4) {
+        const level = std.mem.readInt(i32, buf[0..4], .little);
+        return switch (level) {
+            0 => .nominal,
+            1 => .fair,
+            2 => .serious,
+            else => .critical,
+        };
+    }
+
+    return .nominal;
+}
